-- =====================================================================
-- Seed data for the AI Communication Skills Trainer.
-- Idempotent: each block inserts only when its target table is empty
-- (or the specific rows are absent), so it is safe to run on every boot.
-- Runs after Hibernate creates the schema (defer-datasource-initialization).
-- =====================================================================

-- ---------- Department (single: Migration) ----------
INSERT INTO department (created_at, updated_at, name)
SELECT now(), now(), 'Migration'
WHERE NOT EXISTS (SELECT 1 FROM department);

-- ---------- Teams (single team: Migration) ----------
INSERT INTO team (created_at, updated_at, name, department_id)
SELECT now(), now(), 'Migration', d.id
FROM department d
WHERE d.name = 'Migration'
  AND NOT EXISTS (SELECT 1 FROM team);

-- ---------- Managers ----------
INSERT INTO users (created_at, updated_at, employee_id, name, email, role, department_id, team_id, manager_id)
SELECT now(), now(), v.emp, v.name, v.email, 'MANAGER', d.id, t.id, NULL
FROM (VALUES
    ('CF-1001', 'Abhishek Sakala', 'Abhishek.Sakala@cloudfuze.com')
    ) AS v(emp, name, email)
JOIN department d ON d.name = 'Migration'
JOIN team t ON t.name = 'Migration'
WHERE NOT EXISTS (SELECT 1 FROM users WHERE role = 'MANAGER');

-- ---------- Employees ----------
-- No seeded/demo employees. Real employees are provisioned automatically on their
-- first Microsoft sign-in (see AuthService) and appear in the manager portal, which
-- lists every EMPLOYEE-role user. This keeps the portal showing only real logins.

-- ---------- Listening stories (each ~2 minutes of audio) ----------
INSERT INTO listening_story (created_at, updated_at, title, script)
SELECT now(), now(), v.title, v.script
FROM (VALUES
    ('The Q3 Platform Outage',
     'On Tuesday morning, the CloudFuze platform team joined an emergency call after monitoring alerts fired at nine fifteen AM. The on-call engineer, Priya, reported that the primary database in the Frankfurt region had become unresponsive, and customer file synchronization had stopped for about forty percent of enterprise accounts. The team lead, Daniel, took over as incident commander. Within six minutes, traffic was failed over to the standby replica in Ireland, which restored read access, but uploads were still failing. Investigation showed the root cause was a full disk on the primary node, caused by log files that had not been rotated for three weeks. Neha cleared the logs and expanded the disk, and by ten oh five AM all services were fully restored. In total, the outage lasted fifty minutes. No customer data was lost, but two large migrations scheduled for that morning were delayed to the afternoon. During the retrospective, the team agreed on three action items: add disk usage alerts at eighty percent capacity, automate log rotation across all regions, and document the failover steps in the runbook. Daniel also moved the weekly backup window from midnight to two AM to reduce load. The support team notified the twelve affected enterprise customers by email. Finally, leadership asked for a written incident report to be shared with stakeholders by end of week, and scheduled a review meeting for the following Monday at eleven AM.'),
    ('The Marketing Team Migration',
     'Last month, CloudFuze began migrating the marketing department from Google Drive to Microsoft SharePoint. The project was led by Arjun, with a target completion date of the thirtieth of the month. The department had around eight terabytes of data spread across two hundred shared folders. In the first week, the team moved all individual user drives, which accounted for about sixty percent of the data. However, progress slowed when they reached shared folders with complex permission settings, because many folders had been shared with external partners. To solve this, the team built a mapping script that matched Google permissions to SharePoint roles, which saved an estimated three days of manual work. A pilot group of five marketing managers tested the migrated content and reported that most files opened correctly, though some older design files needed to be reconverted. The team scheduled the final cutover for a Saturday to avoid disrupting business hours, and sent reminder emails to all staff two days in advance. During the cutover, one issue appeared: a batch of video files larger than two gigabytes failed to transfer on the first attempt, but succeeded after the team increased the upload timeout. By Sunday evening, the migration was ninety-eight percent complete, and the remaining files were finished on Monday morning. Arjun sent a completion report to stakeholders and scheduled a feedback session for the following week to capture lessons learned.'),
    ('The Meridian Bank Escalation',
     'On Monday afternoon, a priority-one ticket was raised by Meridian Bank, one of CloudFuze''s largest customers. Their team reported that a scheduled migration of forty thousand user accounts had stalled at sixty percent. The account manager, Sofia, joined a call with the customer within fifteen minutes. The support engineer, Karan, discovered that the migration had paused because the customer''s identity provider was rate-limiting requests to one hundred calls per minute. Karan proposed reducing the migration batch size and adding a short delay between batches. After the customer approved, the migration resumed and completed in about three hours. Sofia sent an update to the customer every hour during the incident. Once resolved, the team scheduled a root-cause review and agreed to add automatic rate-limit detection to the migration tool by the end of the quarter. The customer confirmed they would proceed with the second phase, covering another twenty-five thousand accounts, the following month. The engineering manager praised Karan for resolving the issue without any data loss and asked him to document the workaround in the shared knowledge base so other engineers could reuse it.'),
    ('The Phishing Simulation',
     'Last Thursday, the CloudFuze security team ran a planned phishing simulation across the company. They sent a fake email that appeared to come from the IT department, asking employees to reset their password using a link. Out of five hundred employees, about twelve percent clicked the link, and thirty employees entered their credentials on the fake page. No real accounts were compromised because the page only recorded who fell for it. The security lead, Ibrahim, said the click rate was lower than last year''s twenty percent, showing improvement. The team scheduled a short training session for the employees who entered their credentials and reminded everyone that IT will never ask for passwords by email. They also announced that hardware security keys would be rolled out to all engineers by the end of next month. Ibrahim noted that the finance department had the lowest click rate at three percent, while the newest hires had the highest. As a follow-up, the team decided to run these simulations every quarter instead of once a year, and praised the eight employees who reported the suspicious email within the first ten minutes.'),
    ('The Insights Product Launch',
     'The product team spent three months preparing for the launch of CloudFuze Insights, a new analytics dashboard. The launch was set for the first of the month. Two weeks before, the team ran a closed beta with fifteen customers, who gave mostly positive feedback but asked for a way to export reports to PDF. The team added the export feature just in time. On launch day, the marketing team published a blog post and sent an announcement to twelve thousand subscribers. Within the first week, four hundred customers activated the new dashboard, exceeding the target of three hundred. The most requested feature after launch was scheduled email reports, which the team added to the roadmap for the next release. The support team reported only five minor issues, all resolved within a day. The product manager, Lena, presented the results at the company all-hands and thanked the engineering and design teams. She noted that the average time to set up the dashboard was under five minutes, which was a key goal. Looking ahead, the team plans to add custom charts and to translate the interface into three additional languages by the end of the year.')
    ) AS v(title, script)
WHERE NOT EXISTS (SELECT 1 FROM listening_story);

