-- ---------- Writing prompts ----------
INSERT INTO writing_prompt (created_at, updated_at, category, prompt)
SELECT now(), now(), v.category, v.prompt
FROM (VALUES
    -- Customer emails (prompt 1 is always one of these). Each is a short story with all the facts needed.
    ('Customer Email', 'It is Monday morning. Priya, an IT manager at your customer TechNova, has emailed you worried: their migration of 40,000 files from Google Drive to SharePoint has been stuck at 60 percent since Sunday. Your engineer Karan found the cause — TechNova''s identity provider was rate-limiting the migration to 100 requests per minute. Karan has reduced the batch size and restarted it, and it should now finish in about three hours. No files are at risk. Your task: reply to Priya with an email that explains what happened in simple terms, reassures her, and gives a clear ETA.'),
    ('Customer Email', 'Over the weekend your team migrated all eight terabytes of files for the customer BrightRetail from Dropbox to OneDrive, and every file moved with no data loss. Only a few very old design files could not be converted automatically; you will reconvert those by Monday afternoon. Your task: write an email to the BrightRetail contact confirming the migration is complete and explaining the one small remaining item and when it will be done.'),
    ('Customer Email', 'You promised the customer Meridian Bank their mailbox migration would finish by Friday. On Thursday their email vendor had a major outage that lasted most of the day, so the migration can now only finish on Tuesday. No data is at risk. Your task: write an email to Meridian Bank apologizing for the delay, briefly explaining the cause, and giving a realistic new completion date.'),
    ('Customer Email', 'The customer FinEdge noticed they were charged twice this month for 50 extra user licenses. You checked with billing and confirmed it was a mistake on your side. A full refund for the duplicate charge has already been issued and will appear on their card in five to seven business days. Your task: write an email to FinEdge explaining what happened and confirming the refund and timeline.'),
    ('Customer Email', 'A customer has emailed asking for a refund, but they are asking two weeks after your 14-day refund window closed, so you cannot give a cash refund. You can offer account credit toward their next invoice instead. Your task: write an empathetic but firm email explaining you cannot refund outside the window, and offering the account-credit alternative.'),
    ('Customer Email', 'The customer DataWorks has asked for a feature that automatically emails them scheduled reports. That feature is on the roadmap but will not ship until next quarter. For now, they can export the report manually from the dashboard each week. Your task: write an email to DataWorks setting clear expectations on when the feature will arrive and explaining the manual workaround they can use now.'),
    ('Customer Email', 'While migrating the customer NorthPeak''s shared drives, you found 12 folders that are shared with external partners outside NorthPeak. These cannot be moved safely until NorthPeak decides how the external sharing should be handled. Your task: write an email to NorthPeak explaining what you found and asking how they would like these externally-shared folders handled before you continue.'),
    ('Customer Email', 'Last night the customer Volt Media''s file sync was unavailable for two hours because one of your servers ran out of disk space. Service is now fully restored, and you have added automatic disk-space alerts so it cannot happen again. Your task: write an email to Volt Media explaining the outage, its impact, and the steps you have taken to prevent a repeat.'),
    ('Customer Email', 'The new enterprise customer GlobalTrade begins a large migration next Monday. Before it starts you must confirm three things with them: the cutover date, the read-only freeze window when users cannot edit files, and who their main point of contact will be. Your task: write an email to GlobalTrade confirming these three details and asking them to reply with any corrections.'),
    ('Customer Email', 'The customer Apex Logistics is starting the second phase of their migration and has asked for 25 more user licenses. The extra licenses cost 250 dollars per month and can be activated within one business day of their confirmation. Your task: write an email to Apex confirming the request, stating the new monthly cost, and when the licenses will be active.'),
    -- Varied internal / other prompts (prompt 2 is picked from these).
    ('Internal Escalation', 'It is 4 PM. Sofia, the account manager for your largest customer Meridian Bank, has just messaged you: Meridian''s live migration has completely stopped and their users cannot open any files. You do not yet know the cause. You need the engineering team to investigate immediately. Your task: write an urgent internal message to the engineering team flagging this as priority-one, describing the customer impact clearly, and stating exactly what you need them to do right now.'),
    ('Internal Escalation', 'Your teammate Arjun has been blocked for three days waiting for a customer to grant admin access to their Microsoft 365 tenant. Without it the migration cannot go live this week as promised, and you have already chased the customer twice with no reply. Your task: write an escalation message to your manager explaining the blocker, the impact on the deadline, and what you would like them to do.'),
    ('Incident Report', 'Last night the file-sync service was down for two hours, from 10 PM to midnight, because a server ran out of disk space when log files were not being rotated. About 30 customers were affected. The team freed space and fixed log rotation, and service is back to normal. Your task: write a concise incident report covering the timeline, the root cause, the customer impact, and the remediation taken.'),
    ('Status Update', 'It is Friday afternoon and your manager wants your weekly update. This week you completed the migrations for TechNova and BrightRetail, the FinEdge migration is in progress and about halfway done, and you are blocked waiting on a vendor to fix an API issue. Your task: write a clear weekly status update covering what you completed, what is in progress, and your blocker.'),
    ('Slack Message', 'The staging environment your team uses for testing will be taken down for maintenance tonight from 10 PM to midnight, so no one should rely on it during that window. Your task: write a short, clear Slack message to your team announcing the maintenance window and what to expect.'),
    ('Slack Message', 'You have opened a pull request that fixes a bug where folder permissions were mapped incorrectly during migrations. You need a teammate to review it before 3 PM so it can ship in today''s release. Your task: write a short Slack message asking teammates to review your pull request, explaining what it fixes and why it is time-sensitive.'),
    ('Handover', 'You are going on leave for a week starting tomorrow. You have two active customer migrations — NorthPeak (about 70 percent done) and Volt Media (just started) — and one open support escalation about a billing error. Your task: write a handover note for the colleague covering you, describing each item, its current status, and what they should watch for.'),
    ('Feedback', 'A junior engineer on your team submitted code for review. It works correctly and solves the problem, but it has no automated tests and almost no comments, which will make it hard to maintain. Your task: write constructive code-review feedback that first acknowledges what they did well, then asks for two specific improvements.'),
    ('Meeting Summary', 'You just finished sprint planning. The team committed to the full release scope, deferred the new reporting feature to next sprint, and assigned three action items: Priya on testing, Arjun on documentation, and Neha on the customer demo. Your task: write a clear summary of the meeting that the whole team can refer to later.'),
    ('Vendor Escalation', 'A third-party API your migration tool depends on has been down for three hours, and it is now blocking your release scheduled for this evening. You have had no update from the vendor. Your task: write an escalation email to the vendor requesting an urgent status update and a firm time by which it will be resolved.'),
    ('Proposal', 'Over the last month, three bugs reached customers because pull requests were merged without proper review. You believe a simple mandatory code-review checklist would prevent most of them. Your task: write a short proposal to your team lead to adopt a mandatory code-review checklist, explaining the problem and the benefits you expect.'),
    ('Documentation', 'You have worked out the exact fix for a migration that stalls when a customer''s system rate-limits your requests: reduce the batch size to 25, add a two-second delay between batches, and resume. You want any engineer to apply this without asking you. Your task: write clear runbook documentation describing the problem and the step-by-step fix.'),
    ('Announcement', 'Your company is introducing a new hybrid remote-work policy starting next month: everyone works from the office on Tuesdays and Wednesdays and may work from home the other days. Full details are on the intranet HR page. Your task: write a clear, positive company-wide announcement explaining the change and where people can read the details.'),
    ('Stand-up', 'It is your daily stand-up. Yesterday you finished the OneDrive migration for the customer BrightRetail. Today you will begin migrating their Microsoft Teams channels. You currently have no blockers. Your task: write a brief stand-up update covering yesterday, today, and blockers.'),
    -- More customer emails.
    ('Customer Email', 'The customer Northwind reported that after their migration to SharePoint, several shared links their staff had bookmarked no longer work. You checked: the links simply changed during the move, the files are all safe, and you have prepared a mapping of old links to new ones. Your task: write an email to Northwind reassuring them, explaining why the links changed, and telling them how to get the new links.'),
    ('Customer Email', 'The customer Lakeside Health is worried about security during their migration and has asked how their data is protected while it moves. Your migration encrypts data in transit and at rest, and no data is ever stored on personal devices. Your task: write an email to Lakeside Health clearly explaining how their data is kept secure during the migration.'),
    ('Customer Email', 'The customer Orion Media asked whether they can keep using Google Drive while you migrate them to OneDrive. The answer is yes — during migration both stay available, and only at the final cutover, which you will schedule with them, will Drive become read-only. Your task: write an email to Orion Media answering their question and explaining the cutover.'),
    ('Customer Email', 'You completed a customer''s migration, but a final check showed 3 files failed to copy because another user had them locked at the time. You have re-queued them and they will finish within the hour. Your task: write an email to the customer letting them know the migration is essentially complete and that the 3 files will be finished shortly.'),
    ('Customer Email', 'A customer emailed asking for a status update on their migration, which is 45 percent complete and on track to finish by Thursday. Your task: write a short, reassuring email to the customer giving the current progress and the expected completion date.'),
    ('Customer Email', 'The customer Vertex asked to pause their migration for two days because of an internal audit. That is fine — you can pause and resume with no data loss, and it will add about two days to the timeline. Your task: write an email to Vertex confirming you can pause and explaining the impact on the schedule.'),
    ('Customer Email', 'A customer''s admin, Rahul, emailed thanking your team for a smooth migration and asked for a short summary he can share with his leadership. The migration moved 5 terabytes with zero data loss, finished a day early, and had no downtime. Your task: write a warm email to Rahul with a short summary he can forward to leadership.'),
    ('Customer Email', 'A customer reported that a folder they expected did not appear after migration. You found it was in a personal Google Drive that was never part of the agreed migration scope. Your task: write a polite email to the customer explaining why the folder was not migrated and offering to migrate it as an additional step.'),
    ('Customer Email', 'The customer BlueOrbit goes live tomorrow and has asked what their users need to do on day one. The answer: nothing special — users just sign in to OneDrive with their existing accounts and their files are there. Your task: write a clear, reassuring email to BlueOrbit explaining what their users should expect on the first day.'),
    ('Customer Email', 'A customer''s subscription payment failed and their account will be suspended in three days if it is not fixed. You want to alert them politely so they can update their payment details before any interruption. Your task: write a courteous email to the customer about the failed payment and how to fix it before service is affected.'),
    -- More varied internal / other messages.
    ('Internal Escalation', 'A migration for the customer Zenith has run for 18 hours and is only at 20 percent, far slower than expected. You suspect a performance problem but are not sure, and go-live is tomorrow morning. Your task: write an internal message to the engineering team explaining the slow migration, the deadline risk, and asking them to investigate the performance issue urgently.'),
    ('Status Update', 'Your manager asked for an update on the FinEdge migration. It is 80 percent done, you expect to finish tomorrow, and there is one small risk: a batch of large video files that may need extra time. Your task: write a brief status update covering progress, expected completion, and the one risk.'),
    ('Slack Message', 'You are about to run a large migration in production that could briefly slow the system for other customers between 1 and 2 AM. You want to give the on-call team a heads-up. Your task: write a short Slack message to the on-call channel warning about the possible slowdown and the time window.'),
    ('Incident Report', 'Yesterday a script accidentally sent a test email to 200 real customers. No data was exposed, but it caused confusion and several replies. The script has been fixed and a safeguard added. Your task: write a concise incident report covering what happened, the impact, and the fix.'),
    ('Handover', 'You are handing a customer account to a new account manager, Neha, because you are changing teams. The customer GlobalTrade is mid-migration at 60 percent, generally happy, but sensitive about deadlines. Your task: write a handover note to Neha covering the account status, the customer''s personality, and what to prioritise.'),
    ('Feedback', 'A teammate gave a customer demo that went well overall, but they spoke very fast and skipped the Q&A at the end. You want to help them improve for next time. Your task: write short, constructive feedback acknowledging what went well and suggesting two improvements.'),
    ('Meeting Summary', 'You just finished a customer kickoff call for a new migration. The customer confirmed the scope (10 terabytes, Google to Microsoft 365), agreed to go live in three weeks, and asked for weekly progress emails. Your task: write a clear summary of the kickoff that your team and the customer can refer to.'),
    ('Proposal', 'Support tickets are often delayed because there is no clear owner for each customer. You believe assigning a named owner to every customer would speed up responses. Your task: write a short proposal to your team lead to assign a named owner per customer, explaining the problem and the benefits.'),
    ('Documentation', 'New engineers keep asking how to safely restart a stalled migration. The steps are: pause the job, check the error log, clear the failed batch, then resume from the last checkpoint. Your task: write clear runbook documentation describing when to use this and the exact steps.'),
    ('Announcement', 'Your team is launching a new customer support portal next Monday where customers can track their own migration progress. Your task: write a short, positive internal announcement to the support team explaining the new portal and what it means for them.'),
    ('Status Update', 'It is the end of the day and your team lead wants a quick end-of-day update. Today you resolved two customer escalations, started the NorthPeak migration, and you are waiting on a customer to confirm their cutover window. Your task: write a brief end-of-day update.'),
    ('Stand-up', 'At stand-up: yesterday you fixed the rate-limiting bug that was stalling migrations, today you will help onboard the new customer BlueOrbit, and you are blocked waiting for their admin credentials. Your task: write a brief stand-up update covering yesterday, today, and your blocker.')
    ) AS v(category, prompt)
WHERE NOT EXISTS (SELECT 1 FROM writing_prompt);

-- ---------- Speaking sentences (500 sentences = 50 fixed sets of 10, no overlap between sets) ----------
-- Each user is permanently assigned one set (least-recently-used), so two users never
-- receive the same 10 sentences until all 50 sets are in use.
